from flask import Flask, request, jsonify, redirect
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import string
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# In-memory storage for authorization codes and tokens
auth_codes = {}
access_tokens = {}
clients = {
    "client1": {"client_id": "client1", "client_secret": generate_password_hash("secret123"), "redirect_uris": ["http://localhost:5000/callback"]}
}

def generate_auth_code():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(32))

def generate_access_token():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(64))

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    
    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if client_id not in clients:
        return jsonify({"error": "Invalid client_id"}), 400
    
    if redirect_uri not in clients[client_id]["redirect_uris"]:
        return jsonify({"error": "Invalid redirect_uri"}), 400
    
    if response_type != "code":
        return jsonify({"error": "Invalid response_type"}), 400
    
    # Generate authorization code
    code = generate_auth_code()
    auth_codes[code] = "user123"  # In real scenario, this would be the actual user ID
    
    # Redirect with authorization code
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    
    if not all([grant_type, code, client_id, client_secret]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if grant_type != "authorization_code":
        return jsonify({"error": "Invalid grant_type"}), 400
    
    if code not in auth_codes:
        return jsonify({"error": "Invalid authorization code"}), 400
    
    # Verify client credentials
    if not check_password_hash(clients[client_id]["client_secret"], client_secret):
        return jsonify({"error": "Invalid client credentials"}), 400
    
    # Generate access token
    token = generate_access_token()
    access_tokens[token] = {
        "user_id": auth_codes[code],
        "expires_at": time.time() + 3600  # 1 hour expiration
    }
    
    # Remove used authorization code (for security)
    del auth_codes[code]
    
    return jsonify({
        "access_token": token,
        "token_type": "Bearer",
        "expires_in": 3600
    })

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)